import { Component, OnDestroy, OnInit, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router, RouterModule } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { lastValueFrom, Subscription } from 'rxjs';

import { AuthService } from '../../services/timbrature-auth.adapter';
import { TimbratureService } from '../../services/timbrature.service';
import { UsersService } from '../../services/user.service';
import { CompanyService } from '../../services/company.service';

import { Timbratura, RichiestaModificaTimbratura, User } from '../../models';
import { LUCIDE_ICONS, LucideAngularModule } from 'lucide-angular';

@Component({
  selector: 'app-lista-timbrature',
  standalone: true,
  imports: [CommonModule, RouterModule, FormsModule, LucideAngularModule],
  templateUrl: './lista-timbrature.component.html',
  styleUrls: ['./lista-timbrature.component.css']
})
export class ListaTimbratureComponent implements OnInit, OnDestroy {
  // Servizi
  private authService = inject(AuthService);
  private timbratureService = inject(TimbratureService);
  private usersService = inject(UsersService);
  private companyService = inject(CompanyService);
  private router = inject(Router);

  // Dati principali
  currentUser: User | null = null;
  timbrature: Timbratura[] = [];
  timbratureFiltrate: Timbratura[] = [];
  deletedTimbrature: Timbratura[] = [];
  richiesteModifica: RichiestaModificaTimbratura[] = [];
  userPendingRequests: RichiestaModificaTimbratura[] = [];
  pendingTimbraturaIds = new Set<string>();

  // UI State
  isLoading = false;
  showDeletedSection = false;
  filtroDataInizio = '';
  filtroDataFine = '';
  filtroStato = '';
  filtroOggi = false;

  // Permessi e visibilità manager
  managerCanModifyTimbrature = false;
  visibleEmployeeIds = new Set<string>(); // ID dei dipendenti che il manager può vedere
  managerViewingOthers = false; // true se sta vedendo timbrature di altri

  private subscriptions = new Subscription();

  ngOnInit() {
    this.subscriptions.add(
      this.authService.currentUser$.subscribe(async (user) => {
        this.currentUser = user;
        if (user) {
          await this.initPermissionsAndData();
        } else {
          this.resetData();
        }
      })
    );

    // Sottoscrizione agli aggiornamenti delle richieste (se il servizio emette eventi)
    this.subscriptions.add(
      this.timbratureService.pendingRequests$.subscribe(() => {
        if (this.currentUser) {
          this.loadRichiesteModifica();
        }
      })
    );
  }

  ngOnDestroy() {
    this.subscriptions.unsubscribe();
  }

  private async initPermissionsAndData() {
    if (!this.currentUser) return;

    // Per i manager, calcola permessi e visibilità
    if (this.authService.hasRole('manager')) {
      await this.computeManagerPermissions();
      await this.computeVisibleEmployees();
    }

    // Carica timbrature e richieste in parallelo
    await Promise.all([
      this.loadTimbrature(),
      this.loadRichiesteModifica(),
      this.loadDeletedTimbrature() // pre-carica cestino (senza attesa)
    ]);
  }

  private resetData() {
    this.timbrature = [];
    this.timbratureFiltrate = [];
    this.deletedTimbrature = [];
    this.richiesteModifica = [];
    this.userPendingRequests = [];
    this.pendingTimbraturaIds.clear();
    this.visibleEmployeeIds.clear();
    this.managerCanModifyTimbrature = false;
    this.managerViewingOthers = false;
  }

  // --- Gestione permessi manager ---
  private async computeManagerPermissions() {
    if (!this.currentUser || !this.authService.hasRole('manager')) return;
    try {
      // Ottieni l'azienda
      const company = await lastValueFrom(
        this.companyService.getById(this.currentUser.company_id!)
      );
      // Usa il metodo dell'auth service per controllare il permesso di modifica
      this.managerCanModifyTimbrature = await this.authService.hasManagerPermission(
        'manage_departments', // o un permesso specifico per timbrature? Nel vecchio era "can_modify_timbrature"
        this.currentUser.company_id!
      );

      // Per la visibilità, usiamo la configurazione dell'azienda
      const visibilityMap = (company as any)?.manager_visibility || {};
      const config = visibilityMap[this.currentUser.id] || {};
      const mode = config.mode || 'self';
      const hasLists = (config.user_ids?.length > 0) || (config.roles?.length > 0) || (config.department_ids?.length > 0);
      this.managerViewingOthers = mode !== 'self' || config.can_view_all_employees || hasLists;
    } catch (error) {
      console.error('Errore nel calcolo permessi manager', error);
      this.managerCanModifyTimbrature = false;
      this.managerViewingOthers = false;
    }
  }

  private async computeVisibleEmployees() {
    if (!this.currentUser || !this.authService.hasRole('manager') || !this.authService.companyId) return;
    try {
      // Ottieni tutti i dipendenti dell'azienda
      const companyId = this.authService.companyId!;
      const employees = await lastValueFrom(
        this.usersService.getByCompany(companyId, 'employee')
      );
      const company = await lastValueFrom(
        this.companyService.getById(companyId)
      );
      // Filtra gli ID visibili usando il metodo del companyService (da implementare)
      const visible = this.companyService.filterEmployeesByVisibility(
        employees,
        company,
        this.currentUser.id
      );
      this.visibleEmployeeIds = new Set(visible.map(e => e.id));
    } catch (error) {
      console.error('Errore nel calcolo dipendenti visibili', error);
      this.visibleEmployeeIds.clear();
    }
  }

  // --- Caricamento dati ---
  async loadTimbrature() {
    if (!this.currentUser) return;
    this.isLoading = true;
    try {
      let items: Timbratura[] = [];
      const user = this.currentUser;

      if (this.authService.hasRole('employee')) {
        items = await lastValueFrom(
          this.timbratureService.getFiltered({
            company_id: user.company_id!,
            user_id: user.id
          })
        );
      } else if (this.authService.hasRole('admin')) {
        items = await lastValueFrom(this.timbratureService.getAll(user.company_id ?? undefined));

      } else if (this.authService.hasRole('manager') as any) {
        // Per manager, prendi tutte le timbrature dell'azienda
        const all = await lastValueFrom(this.timbratureService.getAll(user.company_id ?? undefined));
        if (this.managerViewingOthers && this.visibleEmployeeIds.size > 0) {
          items = all.filter(t => this.visibleEmployeeIds.has(t.user_id));
        } else if (this.managerViewingOthers) {
          // Se non ci sono ID visibili (config vuota), mostra tutte (ma forse è un errore)
          items = all;
        } else {
          // Modalità self: solo le proprie
          items = all.filter(t => t.user_id === user.id);
        }
      } else {
        items = [];
      }

      this.timbrature = items || [];
      this.applicaFiltri();

      // Se il manager vede timbrature di altri, arricchisci con i dati utente se non presenti
      if (this.authService.hasRole('manager') as any && this.managerViewingOthers) {
        await this.enrichTimbratureWithUserData();
      }
    } catch (error) {
      console.error('Errore caricamento timbrature', error);
    } finally {
      this.isLoading = false;
    }
  }

  private async enrichTimbratureWithUserData() {
    // Se qualche timbratura non ha il campo 'user' popolato, lo aggiungiamo
    const needEnrich = this.timbrature.some(t => !t.user);
    if (!needEnrich) return;

    try {
      const employees = await lastValueFrom(
        this.usersService.getByCompany(this.currentUser!.company_id!)
      );
      const userMap = new Map(employees.map(u => [u.id, u]));
      this.timbrature = this.timbrature.map(t => ({
        ...t,
        user: t.user || userMap.get(t.user_id)
      }));
      this.applicaFiltri(); // riapplica filtri dopo l'arricchimento
    } catch (error) {
      console.warn('Errore arricchimento dati utente', error);
    }
  }

  async loadDeletedTimbrature() {
    if (!this.currentUser) return;
    try {
      if (this.authService.hasRole('admin')) {
        this.deletedTimbrature = await lastValueFrom(this.timbratureService.getDeletedTimbrature());
      } else {
        this.deletedTimbrature = await lastValueFrom(this.timbratureService.getDeletedTimbrature(this.currentUser.id));
      }

    } catch (error) {
      console.error('Errore caricamento cestino', error);
      this.deletedTimbrature = [];
    }
  }

  async loadRichiesteModifica() {
    if (!this.currentUser) return;
    try {
      const companyId = this.currentUser.company_id;
      const all = await lastValueFrom(
        this.timbratureService.getRichiesteModifica(companyId ?? undefined, 'pending')
      );

      if (this.authService.hasRole('admin')) {
        this.richiesteModifica = all;
      } else if (this.authService.hasRole('manager') && this.managerCanModifyTimbrature) {
        // Manager con permesso: solo richieste dei dipendenti visibili
        if (this.visibleEmployeeIds.size > 0) {
          this.richiesteModifica = all.filter(r =>
            this.visibleEmployeeIds.has(r.user_id || r.timbratura?.user_id || '')
          );
        } else {
          this.richiesteModifica = [];
        }
      } else {
        // Employee o manager senza permesso: solo le proprie richieste
        this.richiesteModifica = all.filter(r =>
          (r.user_id || r.timbratura?.user_id) === this.currentUser!.id
        );
      }

      // Aggiorna anche le richieste pending dell'utente corrente
      this.userPendingRequests = all.filter(r =>
        (r.user_id || r.timbratura?.user_id) === this.currentUser!.id
      );
      this.pendingTimbraturaIds = new Set(
        this.userPendingRequests.map(r => r.timbratura_id || r.timbratura?.id || '')
      );
    } catch (error) {
      console.error('Errore caricamento richieste', error);
    }
  }

  // --- Filtri ---
  applicaFiltri() {
    let filtrate = this.timbrature;

    if (this.filtroDataInizio) {
      const dataInizio = new Date(this.filtroDataInizio);
      filtrate = filtrate.filter(t => new Date(t.start_ts) >= dataInizio);
    }
    if (this.filtroDataFine) {
      const dataFine = new Date(this.filtroDataFine);
      dataFine.setHours(23, 59, 59, 999);
      filtrate = filtrate.filter(t => new Date(t.start_ts) <= dataFine);
    }
    if (this.filtroStato) {
      if (this.filtroStato === 'attiva') {
        filtrate = filtrate.filter(t => !t.end_ts);
      } else if (this.filtroStato === 'completata') {
        filtrate = filtrate.filter(t => !!t.end_ts);
      }
    }
    if (this.filtroOggi) {
      const oggi = new Date();
      oggi.setHours(0, 0, 0, 0);
      const domani = new Date(oggi);
      domani.setDate(domani.getDate() + 1);
      filtrate = filtrate.filter(t => {
        const data = new Date(t.start_ts);
        return data >= oggi && data < domani;
      });
    }

    this.timbratureFiltrate = filtrate;
  }

  filtraOggi() {
    this.filtroOggi = !this.filtroOggi;
    if (this.filtroOggi) {
      this.filtroDataInizio = '';
      this.filtroDataFine = '';
    }
    this.applicaFiltri();
  }

  // --- Azioni sulle timbrature ---
  async nuovaTimbratura() {
    if (!this.currentUser) {
      this.router.navigate(['/crea-timbratura']);
      return;
    }

    try {
      const oggi = new Date();
      oggi.setHours(0, 0, 0, 0);
      const domani = new Date(oggi);
      domani.setDate(domani.getDate() + 1);

      const timbratureOggi = await lastValueFrom(
        this.timbratureService.getFiltered({
          company_id: this.currentUser.company_id!,
          user_id: this.currentUser.id,
          start_ts: {
            gte: oggi.toISOString(),
            lt: domani.toISOString()
          }
        })
      );

      if (timbratureOggi.length > 0) {
        const existing = timbratureOggi[0];
        const ingressTime = new Date(existing.start_ts).toLocaleTimeString('it-IT', {
          hour: '2-digit',
          minute: '2-digit'
        });
        const conferma = confirm(
          `È già presente una timbratura oggi con ingresso alle ${ingressTime}. Vuoi modificarla?`
        );
        if (conferma) {
          this.router.navigate(['/crea-timbratura', existing.id]); // <-- usa il percorso con id
        }
      } else {
        this.router.navigate(['/crea-timbratura']);
      }
    } catch (error) {
      console.error('Errore in nuovaTimbratura', error);
      this.router.navigate(['/crea-timbratura']);
    }
  }

  visualizzaTimbratura(timbratura: Timbratura) {
    this.router.navigate(['/crea-timbratura', timbratura.id], {
      queryParams: { edit: timbratura.id, mode: 'edit' }
    });
  }

  async completaTimbratura(t: Timbratura) {
    if (!t?.id || !this.currentUser) return;

    // Verifica permessi
    const isOwner = t.user_id === this.currentUser.id;
    const canAdmin = this.authService.hasRole('admin');
    const canManager = this.authService.hasRole('manager') && this.managerCanModifyTimbrature;

    if (!(isOwner || canAdmin || canManager)) {
      alert('Non hai i permessi per completare questa timbratura.');
      return;
    }

    const chiudiOra = confirm('Chiudere la timbratura ora? (OK = ora, Annulla = inserisci orario manuale)');
    let endIso: string | null = null;

    if (chiudiOra) {
      endIso = new Date().toISOString();
    } else {
      const input = prompt(
        'Inserisci orario di fine (formati: "YYYY-MM-DD HH:mm" o "HH:mm" per oggi). Esempio: 2025-11-13 18:30'
      );
      if (!input) return;
      endIso = this.parseInputToIso(input);
      if (!endIso) {
        alert('Orario non valido. Operazione annullata.');
        return;
      }
    }

    try {
      this.isLoading = true;
      await lastValueFrom(this.timbratureService.completeTimbratura(t.id, endIso));
      await this.loadTimbrature();
      await this.loadRichiesteModifica(); // aggiorna anche le richieste
    } catch (error) {
      console.error('Errore completamento timbratura', error);
      alert('Errore durante la chiusura.');
    } finally {
      this.isLoading = false;
    }
  }

  private parseInputToIso(input: string): string | null {
    input = input.trim();
    // ISO già valido
    const tryIso = new Date(input);
    if (!isNaN(tryIso.getTime()) && /\d{4}-\d{2}-\d{2}T/.test(input)) {
      return tryIso.toISOString();
    }
    // YYYY-MM-DD HH:mm
    const dtMatch = input.match(/^(\d{4})-(\d{2})-(\d{2})[ T](\d{1,2}):(\d{2})$/);
    if (dtMatch) {
      const [, y, m, d, hh, mm] = dtMatch;
      const dt = new Date(Number(y), Number(m) - 1, Number(d), Number(hh), Number(mm));
      return isNaN(dt.getTime()) ? null : dt.toISOString();
    }
    // HH:mm
    const timeMatch = input.match(/^(\d{1,2}):(\d{2})$/);
    if (timeMatch) {
      const now = new Date();
      const [, hh, mm] = timeMatch;
      const dt = new Date(now.getFullYear(), now.getMonth(), now.getDate(), Number(hh), Number(mm));
      return isNaN(dt.getTime()) ? null : dt.toISOString();
    }
    return null;
  }

  // --- Soft delete e ripristino ---
  async eliminaTimbratura(t: Timbratura) {
    if (!this.currentUser) return;
    const conferma = confirm('Spostare la timbratura nel cestino? (Potrai ripristinarla)');
    if (!conferma) return;

    try {
      await lastValueFrom(this.timbratureService.softDelete(t.id, this.currentUser.id));
      await this.loadTimbrature();
      if (this.showDeletedSection) await this.loadDeletedTimbrature();
    } catch (error) {
      console.error('Errore eliminazione', error);
      alert('Errore durante lo spostamento nel cestino.');
    }
  }

  async ripristinaTimbratura(t: Timbratura) {
    const conferma = confirm('Ripristinare la timbratura?');
    if (!conferma) return;

    try {
      await lastValueFrom(this.timbratureService.restore(t.id));
      await this.loadTimbrature();
      await this.loadDeletedTimbrature();
    } catch (error) {
      console.error('Errore ripristino', error);
      alert('Errore durante il ripristino.');
    }
  }

  toggleShowDeleted() {
    this.showDeletedSection = !this.showDeletedSection;
    if (this.showDeletedSection) this.loadDeletedTimbrature();
  }

  // --- Gestione richieste di modifica ---
  async handleRichiestaAction(richiesta: RichiestaModificaTimbratura, action: 'approve' | 'reject') {
    const conferma = confirm(`Confermi ${action === 'approve' ? 'approvazione' : 'rifiuto'}?`);
    if (!conferma) return;

    // Controllo permessi
    if (this.authService.hasRole('manager') && !this.managerCanModifyTimbrature) {
      alert('Non hai permessi per gestire richieste.');
      return;
    }

    try {
      const adminResponse = this.authService.hasRole('admin')
        ? (action === 'approve' ? 'Approvata da admin' : 'Rifiutata da admin')
        : (action === 'approve' ? 'Approvata da manager' : 'Rifiutata da manager');

      await lastValueFrom(
        this.timbratureService.aggiornaRichiestaModifica(
          richiesta.id,
          action === 'approve' ? 'approved' : 'rejected',
          adminResponse,
          action === 'approve' // applyChanges solo se approve
        )
      );

      // Ricarica dati
      await Promise.all([this.loadTimbrature(), this.loadRichiesteModifica()]);
    } catch (error) {
      console.error('Errore gestione richiesta', error);
      alert('Errore durante l\'operazione.');
    }
  }

  formatRequestedChanges(richiesta: RichiestaModificaTimbratura): { label: string; old: string; newVal: string }[] {
    const out: { label: string; old: string; newVal: string }[] = [];
    if (!richiesta?.requested_changes) return out;

    const rc = richiesta.requested_changes;
    const od = richiesta.original_data || {};

    const fmtDate = (iso?: string | null) => iso ? new Date(iso).toLocaleString() : '—';

    if (rc.start_ts !== undefined) {
      out.push({ label: 'Inizio', old: fmtDate(od.start_ts), newVal: fmtDate(rc.start_ts) });
    }
    if (rc.end_ts !== undefined) {
      out.push({ label: 'Fine', old: fmtDate(od.end_ts), newVal: fmtDate(rc.end_ts) });
    }
    if (rc.notes !== undefined) {
      out.push({ label: 'Note', old: od.notes ?? '—', newVal: rc.notes ?? '—' });
    }
    return out;
  }

  // --- Utility ---
  hasRole(role: string): boolean {
    return this.currentUser?.role === role;
  }

  getInitials(firstName?: string, lastName?: string): string {
    if (!firstName && !lastName) return '?';
    const first = firstName?.charAt(0)?.toUpperCase() || '';
    const last = lastName?.charAt(0)?.toUpperCase() || '';
    return first + last;
  }

  // Metodo per il template (già presente)
  troncaTesto(testo: string, max: number): string {
    if (!testo) return '';
    return testo.length > max ? testo.substring(0, max) + '...' : testo;
  }

  get isAdmin(): boolean { return this.authService.hasRole('admin'); }
  get isManager(): boolean { return this.authService.hasRole('manager'); }
  get isEmployee(): boolean { return this.authService.hasRole('employee'); }

  get canModifyTimbratura(): boolean {
  return this.authService.hasRole('admin') || 
    (this.authService.hasRole('manager') && this.managerCanModifyTimbrature);
}

}
